     5‚Üíimport { type AppLanguage, normalizeLanguage } from './language';
     6‚Üíimport { TRANSLATIONS, type TranslationKey, isTranslationKey } from './translations';
     7‚Üí
     8‚Üítype StorageAreaName = 'sync' | 'local';
     9‚Üí
    10‚Üíconst readStorageValue = async (area: StorageAreaName): Promise<unknown> => {
    11‚Üí  try {
    12‚Üí    const storageArea = browser.storage?.[area];
    13‚Üí    if (storageArea?.get) {
    14‚Üí      const result = await storageArea.get(StorageKeys.LANGUAGE);
    15‚Üí      if (result && typeof result === 'object') {
    16‚Üí        return (result as Record<string, unknown>)[StorageKeys.LANGUAGE];
    17‚Üí      }
    18‚Üí    }
    19‚Üí  } catch {
    20‚Üí    // Fall through to chrome.* fallback below.
    21‚Üí  }
    22‚Üí
    23‚Üí  try {
    24‚Üí    const chromeStorage = chrome?.storage?.[area];
    25‚Üí    if (!chromeStorage?.get) return null;
    26‚Üí    return await new Promise<unknown>((resolve) => {
    27‚Üí      chromeStorage.get(StorageKeys.LANGUAGE, (result) => {
    28‚Üí        if (result && typeof result === 'object') {
    29‚Üí          resolve((result as Record<string, unknown>)[StorageKeys.LANGUAGE]);
    30‚Üí        } else {
    31‚Üí          resolve(null);
    32‚Üí        }
    33‚Üí      });
    34‚Üí    });
    35‚Üí  } catch {
    36‚Üí    return null;
    37‚Üí  }
    38‚Üí};
    39‚Üí
    40‚Üíconst getStoredLanguage = async (): Promise<string | null> => {
    41‚Üí  const syncValue = await readStorageValue('sync');
    42‚Üí  if (typeof syncValue === 'string') return syncValue;
    43‚Üí  const localValue = await readStorageValue('local');
    44‚Üí  if (typeof localValue === 'string') return localValue;
    45‚Üí  return null;
    46‚Üí};
    47‚Üí
    48‚Üí/**
    49‚Üí * Get the current language preference
    50‚Üí * 1. First check user's saved preference in storage
    51‚Üí * 2. Fall back to browser UI language
    52‚Üí * 3. Default to English
    53‚Üí */
    54‚Üíexport async function getCurrentLanguage(): Promise<AppLanguage> {
    55‚Üí  const stored = await getStoredLanguage();
    56‚Üí  if (typeof stored === 'string') {
    57‚Üí    return normalizeLanguage(stored);
    58‚Üí  }
    59‚Üí
    60‚Üí  // Fall back to browser UI language
    61‚Üí  try {
    62‚Üí    const browserLang = browser.i18n.getUILanguage();
    63‚Üí    return normalizeLanguage(browserLang);
    64‚Üí  } catch {
    65‚Üí    return 'en';
    66‚Üí  }
    67‚Üí}
    68‚Üí
    69‚Üí/**
    70‚Üí * Get translation for a key using the current language preference
    71‚Üí * This function works in both React and non-React contexts (e.g., content scripts)
    72‚Üí */
    73‚Üíexport async function getTranslation(key: TranslationKey): Promise<string> {
    74‚Üí  const language = await getCurrentLanguage();
    75‚Üí  return TRANSLATIONS[language][key] ?? TRANSLATIONS.en[key] ?? key;
    76‚Üí}
    77‚Üí
    78‚Üí/**
    79‚Üí * Get translation synchronously using cached language
    80‚Üí * This is less accurate but faster for scenarios where async is not possible
    81‚Üí */
    82‚Üílet cachedLanguage: AppLanguage | null = null;
    83‚Üí
    84‚Üíexport function getTranslationSync(key: TranslationKey): string {
    85‚Üí  const language = cachedLanguage || 'en';
    86‚Üí  return TRANSLATIONS[language][key] ?? TRANSLATIONS.en[key] ?? key;
    87‚Üí}
    88‚Üí
    89‚Üíexport function getTranslationSyncUnsafe(key: string): string {
    90‚Üí  if (!isTranslationKey(key)) return key;
    91‚Üí  return getTranslationSync(key);
    92‚Üí}
    93‚Üí
    94‚Üí/**
    95‚Üí * Initialize the i18n system and cache the current language
    96‚Üí * Should be called early in the application lifecycle
    97‚Üí */
    98‚Üíexport async function initI18n(): Promise<void> {
    99‚Üí  cachedLanguage = await getCurrentLanguage();
   100‚Üí
   101‚Üí  // Listen for language changes
   102‚Üí  browser.storage.onChanged.addListener((changes, areaName) => {
   103‚Üí    const next = changes[StorageKeys.LANGUAGE]?.newValue;
   104‚Üí    if ((areaName === 'sync' || areaName === 'local') && typeof next === 'string') {
   105‚Üí      cachedLanguage = normalizeLanguage(next);
   106‚Üí    }
   107‚Üí  });
   108‚Üí}
   109‚Üí
   110‚Üí/**
   111‚Üí * Immediately update the cached language value.
   112‚Üí * This should be called after setting the language in storage to ensure
   113‚Üí * synchronous translation calls use the new language immediately,
   114‚Üí * avoiding race conditions with the async storage.onChanged listener.
   115‚Üí */
   116‚Üíexport function setCachedLanguage(lang: AppLanguage): void {
   117‚Üí  cachedLanguage = lang;
   118‚Üí}
   119‚Üí
   120‚Üí/**
   121‚Üí * Create a translator function that uses cached language
   122‚Üí * This is useful for classes that need a simple t() function
   123‚Üí */
   124‚Üíexport function createTranslator(): (key: string) => string {
   125‚Üí  return (key: string) => getTranslationSyncUnsafe(key);
   126‚Üí}
